// Named exports — preferred
export function createUser(data: UserData): User { ... }
export const USER_ROLES = ['admin', 'user'] as const;
export type UserRole = typeof USER_ROLES[number];

// Default only for framework requirements
export default function Page() { ... }

import { z } from 'zod';

// Runtime schema with inferred TypeScript type
const UserSchema = z.object({
  id: z.string().uuid(),
  email: z.string().email(),
  name: z.string().min(2).max(100),
  role: z.enum(['admin', 'user', 'guest']),
});
type User = z.infer<typeof UserSchema>;

// Discriminated union type guard
type Result<T, E = Error> =
  | { success: true; data: T }
  | { success: false; error: E };

function handleResult<T>(result: Result<T>): T {
  if (result.success) return result.data;
  throw result.error;
}

interface UserCardProps {
  user: User;
  onEdit?: (id: string) => void;
  className?: string;
}

export function UserCard({ user, onEdit, className }: UserCardProps): React.ReactElement {
  const handleEdit = () => { onEdit?.(user.id); };
  return (
    <div className={cn('card', className)}>
      <h3>{user.name}</h3>
      {onEdit && <button onClick={handleEdit}>Edit</button>}
    </div>
  );
}

interface UseUserResult {
  user: User | null;
  isLoading: boolean;
  error: Error | null;
  refetch: () => Promise<void>;
}

export function useUser(userId: string): UseUserResult {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  const refetch = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      setUser(await fetchUser(userId));
    } catch (err) {
      setError(err instanceof Error ? err : new Error('Unknown error'));
    } finally {
      setIsLoading(false);
    }
  }, [userId]);

  useEffect(() => { void refetch(); }, [refetch]);
  return { user, isLoading, error, refetch };
}

const AuthContext = createContext<AuthContextValue | null>(null);

export function useAuth(): AuthContextValue {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within AuthProvider');
  return context;
}

export class AppError extends Error {
  constructor(
    message: string,
    public statusCode: number = 500,
    public code: string = 'INTERNAL_ERROR',
    public isOperational: boolean = true,
  ) {
    super(message);
    this.name = this.constructor.name;
    Error.captureStackTrace(this, this.constructor);
  }
}

export class NotFoundError extends AppError {
  constructor(message = 'Resource not found') {
    super(message, 404, 'NOT_FOUND');
  }
}

export class ValidationError extends AppError {
  constructor(message = 'Validation failed', public errors: Record<string, string[]> = {}) {
    super(message, 400, 'VALIDATION_ERROR');
  }
}

import { type ErrorRequestHandler } from 'express';
import { AppError } from '../utils/errors';
import { ZodError } from 'zod';

export const errorHandler: ErrorRequestHandler = (err, _req, res, _next) => {
  if (err instanceof ZodError) {
    res.status(400).json({ error: 'Validation failed', code: 'VALIDATION_ERROR',
      details: err.flatten().fieldErrors });
    return;
  }
  if (err instanceof AppError && err.isOperational) {
    res.status(err.statusCode).json({ error: err.message, code: err.code });
    return;
  }
  // Never leak internal details to clients
  res.status(500).json({ error: 'Internal server error', code: 'INTERNAL_ERROR' });
};

// vitest.config.ts
import { defineConfig } from 'vitest/config';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  test: {
    globals: true,
    environment: 'jsdom',
    setupFiles: './src/test/setup.ts',
    coverage: { provider: 'v8', reporter: ['text', 'json', 'html'],
      exclude: ['node_modules/', 'src/test/'] },
  },
});

// test/mocks/handlers.ts
import { http, HttpResponse } from 'msw';

export const handlers = [
  http.get('/api/users', () =>
    HttpResponse.json({ users: [{ id: '1', name: 'John' }] })),
  http.post('/api/users', async ({ request }) => {
    const body = await request.json();
    return HttpResponse.json({ id: '3', ...body }, { status: 201 });
  }),
];

// test/setup.ts
import { beforeAll, afterEach, afterAll } from 'vitest';
import { setupServer } from 'msw/node';
import { handlers } from './mocks/handlers';
const server = setupServer(...handlers);
beforeAll(() => server.listen({ onUnhandledRequest: 'error' }));
afterEach(() => server.resetHandlers());
afterAll(() => server.close());

import { vi, type Mock } from 'vitest';
import { fetchUsers } from './api';

vi.mock('./api', () => ({ fetchUsers: vi.fn() }));

describe('getUsers', () => {
  const mockFetch = fetchUsers as Mock;
  beforeEach(() => { vi.clearAllMocks(); });

  it('returns users from API', async () => {
    mockFetch.mockResolvedValue([{ id: '1', name: 'John' }]);
    const result = await getUsers();
    expect(result).toEqual([{ id: '1', name: 'John' }]);
  });
});
